<?php
namespace Tests\Feature;
use App\Domain\Characters\CharacterStatsCalculator;use App\Domain\Equipment\CharacterEquipmentService;use App\Models\Character;use App\Models\Item;use App\Models\ItemInstance;use App\Models\RefinementStatModifier;use App\Models\User;use Database\Seeders\VisualTestingSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use Illuminate\Support\Facades\Schema;use Illuminate\Support\Str;use Tests\TestCase;
class RefinementStatModifierTest extends TestCase{use RefreshDatabase;private function equipped($level=3,$type='weapon',$slot='main_hand',$bonuses=[]){$character=Character::factory()->for(User::factory())->create(['base_attack'=>10,'current_health'=>90]);$item=Item::create(array_merge(['code'=>'refined_'.Str::random(8),'name'=>'Refined item','item_type'=>'equipment','equipment_type'=>$type,'rarity'=>'common','is_stackable'=>false,'max_stack'=>1,'status'=>'active'],$bonuses));$instance=ItemInstance::factory()->create(['character_id'=>$character->id,'item_id'=>$item->id,'refinement_level'=>$level]);app(CharacterEquipmentService::class)->equip($character,$instance->uuid,$slot);return[$character,$item,$instance];}public function test_schema_engine_collation_and_unique_level(){ $this->assertTrue(Schema::hasColumns('refinement_stat_modifiers',['refinement_level','stat_increase_basis_points','status']));$table=DB::selectOne("SELECT ENGINE,TABLE_COLLATION FROM information_schema.TABLES WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME='refinement_stat_modifiers'");$this->assertSame('InnoDB',$table->ENGINE);$this->assertSame('utf8mb4_unicode_ci',$table->TABLE_COLLATION);RefinementStatModifier::create(['refinement_level'=>1,'stat_increase_basis_points'=>1000,'status'=>'active']);$this->expectException(\Illuminate\Database\QueryException::class);RefinementStatModifier::create(['refinement_level'=>1,'stat_increase_basis_points'=>2000,'status'=>'active']);}public function test_effective_is_base_plus_equipment_base_plus_refinement_without_healing(){RefinementStatModifier::create(['refinement_level'=>3,'stat_increase_basis_points'=>5000,'status'=>'active']);list($character)=$this->equipped(3,'weapon','main_hand',['attack_bonus'=>4,'max_health_bonus'=>20]);$result=app(CharacterStatsCalculator::class)->breakdown($character);$this->assertSame(4,$result->equipmentBase()->attack());$this->assertSame(2,$result->refinement()->attack());$this->assertSame(6,$result->equipment()->attack());$this->assertSame(16,$result->effective()->attack());$this->assertSame(90,$character->fresh()->current_health);$this->assertSame(2,$result->toSnapshotArray()['schema_version']);$source=$result->equipmentSources()[0];$this->assertSame($source['total_bonuses'],$source['bonuses']);$this->assertSame('refined_',substr($source['item_code'],0,8));}public function test_missing_and_inactive_modifiers_apply_zero_and_only_one_modifier_query(){RefinementStatModifier::create(['refinement_level'=>3,'stat_increase_basis_points'=>3000,'status'=>'inactive']);list($character)=$this->equipped(3,'weapon','main_hand',['attack_bonus'=>10]);$queries=0;DB::listen(function($query)use(&$queries){if(stripos($query->sql,'refinement_stat_modifiers')!==false)$queries++;});$result=app(CharacterStatsCalculator::class)->breakdown($character);$this->assertSame(10,$result->equipment()->attack());$this->assertFalse($result->equipmentSources()[0]['refinement_modifier_configured']);$this->assertSame(1,$queries);}public function test_visual_testing_seeder_is_idempotent_and_keeps_database_separate(){ $this->seed(VisualTestingSeeder::class);$this->seed(VisualTestingSeeder::class);$this->assertSame(15,RefinementStatModifier::count());$this->assertSame(15000,RefinementStatModifier::where('refinement_level',15)->value('stat_increase_basis_points'));}}
